('a0000001-0001-4000-8000-000000000008', 'organisation', 'Dark Matter Labs', 'A field laboratory for institutional innovation.', 'promoted', 5, 'strong_evidence', ARRAY['formation', 'capital_strategy'], '{"title":"Dark Matter Labs","summary":"A field laboratory redesigning institutional infrastructure for civilisational transition. Works on outcome accelerators, ex-stitutions, self-sovereign land, civic registries, and the Civilization Options Fund.","structured_claim":null,"assumption_type":null,"entities":[{"name":"Dark Matter Labs","type":"organisation"},{"name":"Madrid","type":"site"},{"name":"Helsinki","type":"site"},{"name":"Copenhagen","type":"site"}],"domain_tags":["formation","capital_strategy"],"open_questions":[],"confidence_assessment":{"level":5,"basis":"strong_evidence"},"suggested_connections":[]}'::jsonb, NOW() - INTERVAL '7 days');
